concept.syntax:
// Immutable borrow — read-only
fn show(s: &String) {
    println!("{}", s);
}
let s = String::from("hi");
show(&s);   // lend s; s still owned by caller

// Mutable borrow — can modify
fn append(s: &mut String) {
    s.push_str(" world");
}
let mut s = String::from("hello");
append(&mut s);

demo.code:
fn length(s: &String) -> usize {
    s.len()
}

fn append(s: &mut String) {
    s.push_str(" world");
}

fn main() {
    let mut s = String::from("hello");
    let len = length(&s);
    println!("len = {}", len);
    append(&mut s);
    println!("{}", s);
}

